    public function handle_message(Client $client, $message) {
        //
        // confirmation
        //
        //  {
        //     jsonrpc => '2.0',
        //     result => array(
        //         stream => 'v1.mini.d',
        //         subs => array( 'BTC_USDT_Perp@500' ),
        //         unsubs => array(),
        //         num_snapshots => array( 1 ),
        //         first_sequence_number => array( '1061214' ),
        //         latest_sequence_number => array( '1061213' )
        //     ),
        //     id => 1,
        //     $method => 'subscribe'
        //  }
        //
        // ticker
        //
        //  {
        //     stream => "v1.mini.d",
        //     selector => "BTC_USDT_Perp@500",
        //     sequence_number => "0",
        //     feed => array(
        //         event_time => "1767198134519661154",
        //         instrument => "BTC_USDT_Perp",
        //         ...
        //     ),
        //     prev_sequence_number => "0",
        //  }
        //
        if ($this->handle_error_message($client, $message)) {
            return;
        }
        $methods = array(
            'v1.ticker.s' => array($this, 'handle_ticker'),
            'v1.ticker.d' => array($this, 'handle_ticker'),
            'v1.mini.d' => array($this, 'handle_ticker'),
            'v1.mini.s' => array($this, 'handle_ticker'),
            'v1.trade' => array($this, 'handle_trades'),
            'v1.candle' => array($this, 'handle_ohlcv'),
            'v1.book.s' => array($this, 'handle_order_book'),
            'v1.book.d' => array($this, 'handle_order_book'),
            'v1.fill' => array($this, 'handle_my_trade'),
            'v1.position' => array($this, 'handle_position'),
            'v1.order' => array($this, 'handle_order'),
        );
        $methodName = $this->safe_string($message, 'method');
        if ($methodName === 'subscribe') {
            // return from confirmation
            return;
        }
        $channel = $this->safe_string($message, 'stream');
        $method = $this->safe_value($methods, $channel);
        if ($method !== null) {
            $method($client, $message);
        }
    }

    public function subscribe_multiple(array $messageHashes, array $request, array $rawHashes, $publicOrPrivate = true): PromiseInterface {
        return Async\async(function () use ($messageHashes, $request, $rawHashes, $publicOrPrivate) {
            $payload = array(
                'jsonrpc' => '2.0',
                'method' => 'subscribe',
                'params' => $request,
                'id' => $this->request_id(),
            );
            $apiPart = $publicOrPrivate ? 'publicMarket' : 'privateTrading';
            return Async\await($this->watch_multiple($this->urls['api']['ws'][$apiPart], $messageHashes, $payload, $rawHashes));
        }) ();
    }

    public function request_id() {
        $this->lock_id();
        $newValue = $this->sum($this->safe_integer($this->options, 'requestId', 0), 1);
        $this->options['requestId'] = $newValue;
        $this->unlock_id();
        return $newValue;
    }

    public function watch_ticker(string $symbol, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $params) {
            /**
             * watches a price ticker, a statistical calculation with the information calculated over the past 24 hours for a specific market
             *
             * @see https://api-docs.grvt.io/market_data_streams/#mini-ticker-snap-feed-selector
             *
             * @param {string} $symbol unified $symbol of the market to fetch the ticker for
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a ~@link https://docs.ccxt.com/?id=ticker-structure ticker structure~
             */
            Async\await($this->load_markets());
            $symbol = $this->symbol($symbol);
            $tickers = Async\await($this->watch_tickers(array( $symbol ), $this->extend($params, array( 'callerMethodName' => 'watchTicker' ))));
            return $tickers[$symbol];
        }) ();
    }

    public function watch_tickers(?array $symbols = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbols, $params) {
            /**
             * watches a price $ticker, a statistical calculation with the information calculated over the past 24 hours for all markets of a specific list
             *
             * @see https://docs.backpack.exchange/#tag/Streams/Public/Ticker
             *
             * @param {string[]} $symbols unified $symbol of the $market to fetch the $ticker for
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a ~@link https://docs.ccxt.com/?id=$ticker-structure $ticker structure~
             */
            if ($symbols === null) {
                throw new ArgumentsRequired($this->id . ' watchTickers requires a $symbols argument');
            }
            $channel = null;
            list($channel, $params) = $this->handle_option_and_params($params, 'watchTickers', 'channel', 'v1.ticker.s');
            $interval = null;
            list($interval, $params) = $this->handle_option_and_params($params, 'watchTickers', 'interval', 500);
            Async\await($this->load_markets());
            $symbols = $this->market_symbols($symbols);
            $rawHashes = array();
            $messageHashes = array();
            for ($i = 0; $i < count($symbols); $i++) {
                $symbol = $symbols[$i];
                $market = $this->market($symbol);
                $marketId = $market['id'];
                $rawHashes[] = $marketId . '@' . (string) $interval;
                $messageHashes[] = 'ticker::' . $market['symbol'];
            }
            $request = array(
                'stream' => $channel,
                'selectors' => $rawHashes,
            );
            $ticker = Async\await($this->subscribe_multiple($messageHashes, $this->extend($params, $request), $rawHashes));
            if ($this->newUpdates) {
                $tickers = array();
                $tickers[$ticker['symbol']] = $ticker;
                return $tickers;
            }
            return $this->filter_by_array($this->tickers, 'symbol', $symbols);
        }) ();
    }

